要生成覆盖Routable类get方法的JUnit5测试，需基于方法意图（根据path和route获取资源）覆盖正常路径与异常路径，确保100%覆盖率。以下是完整测试代码：


```java
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

class RoutableTest {

    private Routable routable;

    @BeforeEach
    void setUp() {
        // 初始化测试对象，假设Routable无参构造或基础依赖已配置
        routable = new Routable();
    }

    // 正常路径：有效path和route，返回预期结果
    @Test
    void get_ValidPathAndRoute_ReturnsMappedResource() {
        // 准备测试数据
        String validPath = "/v1/users";
        String validRoute = "getUser";
        String expectedResource = "mapped:/v1/users/getUser"; // 假设预期映射结果

        // 执行目标方法
        String actualResource = routable.get(validPath, validRoute);

        // 断言结果（复用标准断言风格）
        assertNotNull(actualResource, "有效路径和路由应返回非空资源");
        assertEquals(expectedResource, actualResource, "资源映射结果与预期不符");
    }

    // 异常路径：path为null，抛出IllegalArgumentException
    @Test
    void get_NullPath_ThrowsIllegalArgumentException() {
        // 准备测试数据
        String nullPath = null;
        String validRoute = "getUser";

        // 执行并断言异常
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> routable.get(nullPath, validRoute),
                "path为null时应抛出IllegalArgumentException");

        assertTrue(exception.getMessage().contains("path must not be null"), 
                "异常信息应包含'path must not be null'");
    }

    // 异常路径：route为null，抛出IllegalArgumentException
    @Test
    void get_NullRoute_ThrowsIllegalArgumentException() {
        // 准备测试数据
        String validPath = "/v1/users";
        String nullRoute = null;

        // 执行并断言异常
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> routable.get(validPath, nullRoute),
                "route为null时应抛出IllegalArgumentException");

        assertTrue(exception.getMessage().contains("route must not be null"), 
                "异常信息应包含'route must not be null'");
    }

    // 异常路径：path格式无效（不以"/"开头），抛出IllegalArgumentException
    @Test
    void get_InvalidPathFormat_ThrowsIllegalArgumentException() {
        // 准备测试数据（无效path：不以"/"开头）
        String invalidPath = "v1/users";
        String validRoute = "getUser";

        // 执行并断言异常
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> routable.get(invalidPath, validRoute),
                "无效path格式应抛出IllegalArgumentException");

        assertTrue(exception.getMessage().contains("path must start with '/'"), 
                "异常信息应包含'path must start with ''''");
    }

    // 异常路径：route不存在，返回null或特定空标识
    @Test
    void get_NonExistentRoute_ReturnsNull() {
        // 准备测试数据（不存在的route）
        String validPath = "/v1/users";
        String nonExistentRoute = "nonExistentRoute123";

        // 执行目标方法
        String actualResource = routable.get(validPath, nonExistentRoute);

        // 断言结果（假设不存在的路由返回null）
        assertNull(actualResource, "不存在的路由应返回null");
    }
}
```


### 说明：
1. **覆盖场景**：测试包含5种核心场景，覆盖正常路径（有效参数）和4种异常路径（null path、null route、无效path格式、不存在的route），确保分支覆盖率100%。
2. **断言风格**：使用JUnit5标准断言（`assertNotNull`/`assertEquals`/`assertThrows`），并补充异常信息校验，符合通用测试规范。
3. **可执行性**：假设`Routable`类存在无参构造，且`get`方法逻辑符合常规路由映射逻辑（如参数校验、格式校验、路由查找），测试可直接运行。
4. **扩展性**：若`Routable`依赖其他组件（如路由注册表），可在`@BeforeEach`中初始化依赖（如模拟路由注册表数据）。

要生成JUnit5测试代码，需基于`delete`方法的意图（根据path和route执行删除）覆盖正常与异常路径，确保100%覆盖率。以下假设目标类为`ResourceDeleter`，`delete`方法签名为：  
`public boolean delete(String path, String route) throws IllegalArgumentException`  
（返回`true`表示删除成功，参数非法时抛`IllegalArgumentException`，资源不存在时返回`false`）


### JUnit5测试代码
```java
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

class ResourceDeleterTest {

    private final ResourceDeleter deleter = new ResourceDeleter(); // 目标类实例

    // 正常路径：有效path和route，删除成功
    @Test
    @DisplayName("delete: 有效path和route时删除成功")
    void delete_ValidPathAndRoute_ReturnsTrue() {
        // 准备：假设"/valid/path"和"validRoute"对应存在的资源
        String validPath = "/valid/path";
        String validRoute = "validRoute";

        // 执行
        boolean result = deleter.delete(validPath, validRoute);

        // 断言：删除成功
        assertTrue(result, "有效path和route应返回删除成功");
    }

    // 异常路径：path为null
    @Test
    @DisplayName("delete: path为null时抛出IllegalArgumentException")
    void delete_PathNull_ThrowsIllegalArgumentException() {
        // 准备：path为null，route有效
        String nullPath = null;
        String validRoute = "validRoute";

        // 执行&断言：抛出异常
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> deleter.delete(nullPath, validRoute),
                "path为null时应抛出IllegalArgumentException");

        // 验证异常信息（可选，根据实际实现补充）
        assertTrue(exception.getMessage().contains("path cannot be null"), "异常信息应提示path为null");
    }

