public class StatusValidator {
    // 假设有效状态为：1（启用）、2（禁用）、3（待审核）
    private static final Set<Integer> VALID_STATUSES = Set.of(1, 2, 3);

    /**
     * 判断指定status是否存在（即是否为有效状态）
     * @param status 待检查的状态值
     * @return true：存在（有效），false：不存在（无效）
     * @throws IllegalArgumentException 当status为负数时抛出
     */
    public boolean existsFor(int status) {
        if (status < 0) {
            throw new IllegalArgumentException("Status cannot be negative");
        }
        return VALID_STATUSES.contains(status);
    }
}
