```java
public class ConfigManager {
    /**
     * 配置指定目录（创建目录、加载配置等）
     * @param directoryPath 目标目录路径
     * @return 配置是否成功
     * @throws IllegalArgumentException 当路径为null或空时抛出
     * @throws IOException 当路径为文件或目录创建失败时抛出
     */
    public boolean configure(String directoryPath) throws IOException {
        if (directoryPath == null || directoryPath.trim().isEmpty()) {
            throw new IllegalArgumentException("目录路径不能为空");
        }
        File dir = new File(directoryPath);
        if (dir.exists() && !dir.isDirectory()) {
            throw new IOException("路径不是目录: " + directoryPath);
        }
        if (!dir.exists() && !dir.mkdirs()) {
            throw new IOException("目录创建失败: " + directoryPath);
        }
        // 此处省略配置加载逻辑（如读取配置文件等）
        return true;
    }
}
```


